OnOpenPage()

{

	// Add your component and variables initialization code here

	// WARNING: All variables definied on this function are global for this page



   if( IsProject() == 0 )

   {

      CString mHistory;

      mHistory.SetString("w_tan.bdf");

   }



   int grajDuze = 0;



   int maxKlatek =  1844;



   LoadGroup("g_tan.grp");

   SetCursor(-3);



   int toolbar=0;

   int toolbarCase=0;

   Group.HotSpot_Holder.DisableHotSpot(1);



   //SetTimer(5000);

   FadeScreen( 1, 1000 );



   Sprite_Holder.ChangePhase( 7, 1 );

}





void OnTimer(void)

{

	// Add your timer handler code here

   SetTimer(0);

   Video_Holder.Stop();

   grajDuze = 0;



   CreateDirectSound();

   Group.Sound_Holder.PlayDSound( 0 );

}



void OnKeyDown(UINT nChar)

{

	// Add your keyboard handler code here



}



void OnClosePage(void)

{

	// Add your close page handler code here

   FadeScreen( 0, 1000 );



   Video_Holder.Stop();



   CreateDirectSound();

   CloseGroup();

}







